import React from 'react';
import lab from "../assets/Lab Workspace.png";
import schoolWorkshop from "../assets/School Workshop.png";

export function About() {
  return (
    <section id="about" style={{ background: '#fff', padding: '40px 5%' }}>
      <div style={{ display: 'flex', gap: 24, flexWrap: 'wrap' }}>
        {/* Left Card */}
        <div style={{ flex: '1 1 300px', position: 'relative', overflow: 'hidden' }}>
          <img
            src={lab}
            alt="Lab Workspace"
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              position: 'absolute',
              top: 0,
              left: 0
            }}
          />
          <div style={{
            position: 'absolute',
            inset: 0,
            background: 'linear-gradient(to top, rgba(0,0,0,0.5), transparent)'
          }} />
          <div style={{ position: 'relative', padding: 20, color: '#fff', zIndex: 1 }}>
            <h3>Lab Workspace</h3>
            <p>Innovative research and development environment.</p>
          </div>
        </div>

        {/* Right Card */}
        <div style={{ flex: '1 1 300px', position: 'relative', overflow: 'hidden' }}>
          <img
            src={schoolWorkshop}
            alt="School Workshop"
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              position: 'absolute',
              top: 0,
              left: 0
            }}
          />
          <div style={{
            position: 'absolute',
            inset: 0,
            background: 'linear-gradient(to top, rgba(0,0,0,0.5), transparent)'
          }} />
          <div style={{ position: 'relative', padding: 20, color: '#fff', zIndex: 1 }}>
            <h3>School Workshop</h3>
            <p>Hands-on learning experiences for students.</p>
          </div>
        </div>
      </div>
    </section>
  );
}
